/// Describes a PHI node that may or may not exist. These track the PHIs
/// that must be created if we sunk a sequence of instructions. It provides
/// a hash function for efficient equality comparisons.
class ModelledPHI {
  SmallVector<Value *, 4> Values;
  SmallVector<BasicBlock *, 4> Blocks;

public:
  ModelledPHI() = default;

  ModelledPHI(const PHINode &P) {
    for (unsigned I = 0, E = P.getNumIncomingValues(); I != E; ++I) {
      Values.push_back(P.getIncomingValue(I));
      Blocks.push_back(P.getIncomingBlock(I));
    }
  }

  void restrictToBlocks(const SmallPtrSetImpl<BasicBlock *> &BlockSet) {
    SmallVector<Value *, 4> NewValues;
    SmallVector<BasicBlock *, 4> NewBlocks;
    for (unsigned I = 0, E = Blocks.size(); I != E; ++I) {
      if (BlockSet.count(Blocks[I])) {
        NewValues.push_back(Values[I]);
        NewBlocks.push_back(Blocks[I]);
      }
    }
    Values = NewValues;
    Blocks = NewBlocks;
  }

  ArrayRef<Value *> getValues() const { return Values; }

  bool operator==(const ModelledPHI &Other) const {
    return Values == Other.Values && Blocks == Other.Blocks;
  }
};

} // end anonymous namespace

namespace llvm {
template <> struct DenseMapInfo<ModelledPHI> {
  static inline ModelledPHI getEmptyKey() {
    return *reinterpret_cast<ModelledPHI *>(~static_cast<uintptr_t>(0));
  }
  static inline ModelledPHI getTombstoneKey() {
    return *reinterpret_cast<ModelledPHI *>(~static_cast<uintptr_t>(1));
  }
  static unsigned getHashValue(const ModelledPHI &M) {
    return static_cast<unsigned>(hash_combine_range(
        M.getValues().begin(), M.getValues().end(),
        hash_combine_range(M.getValues().begin(), M.getValues().end())));
  }
  static bool isEqual(const ModelledPHI &LHS, const ModelledPHI &RHS) {
    if (isEqual(LHS, getEmptyKey()) || isEqual(LHS, getTombstoneKey()) ||
