  if (ActivePreds.size() != InitialActivePredSize) {
    ModelledPHISet NewNeededPHIs;
    for (auto P : NeededPHIs) {
      P.restrictToBlocks(ActivePreds);
      NewNeededPHIs.insert(P);
    }
    NeededPHIs = NewNeededPHIs;
    LRI.restrictToBlocks(ActivePreds);
    RecomputePHIContents = true;
  }

  Instruction *I0 = NewInsts[0];
  // Don't sink instructions that are not cloneable, such as those that
  // have unique side-effects.
  if (!I0->isCloneable())
    return std::nullopt;

  // Don't sink instructions that are non-trivial to sink, such as those
  // with many uses.
  if (!I0->hasOneUse())
    return std::nullopt;

  // Don't sink instructions that have uses outside of the successor block.
  // FIXME: This is overly restrictive.
  if (PHIContents.count(I0))
    return std::nullopt;

