  // active predecessors.
  if (RecomputePHIContents) {
    PHIContents.clear();
    for (auto P : NeededPHIs)
      for (auto V : P.getValues())
        PHIContents.insert(V);
  }

  // Check that all operands are either defined outside of the sinking blocks
  // or are PHI-able.
  for (unsigned O = 0, E = I0->getNumOperands(); O != E; ++O) {
    bool NeedsPHI = false;
    for (auto *I : NewInsts) {
      if (I->getOperand(O) != I0->getOperand(O)) {
        NeedsPHI = true;
        break;
      }
    }
    if (!NeedsPHI)
      continue;

    SmallVector<Value *, 4> Operands;
    for (auto *I : NewInsts)
      Operands.push_back(I->getOperand(O));
    ModelledPHI P;
    NeededPHIs.insert(P);
    PHIContents.insert_range(P.getValues());
  }

  if (isMemoryInst(NewInsts[0]))
    ++MemoryInstNum;

  SinkingInstructionCandidate Cand;
  Cand.NumInstructions = ++InstNum;
  Cand.NumMemoryInsts = MemoryInstNum;

